INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Return Push from Stance', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['You will need a partner for this drill.','Begin in an athletic 2 or 3 point stance.','At the signal, move into a position to receive the pass from your partner.','Catch the medicine ball with both hands and immediately throw it back to your partner.','You can modify this drill by running different routes.'], ARRAY['shoulders'], ARRAY['chest','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Band Bench Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Position a bench inside a power rack, with the bar set to the correct height. Begin by anchoring bands either to band pegs or to the top of the rack. Ensure that you will be position properly under the bands. Attach the other end to the barbell.','Lie on the bench, tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. However wide your grip, it should cover the ring on the bar.','Pull the bar out of the rack without protracting your shoulders. Focus on squeezing the bar and trying to pull it apart. Lower the bar to your lower chest or upper stomach. The bar, wrist, and elbow should stay in line at all times.','Pause when the barbell touches your torso, and then drive the bar up with as much force as possible. The elbows should be tucked in until lockout.'], ARRAY['triceps'], ARRAY['chest','forearms','lats','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Band Box Squat', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin in a power rack with a box at the appropriate height behind you. Set up the bands either on band pegs or attached to the top of the rack, ensuring they will be directly above the bar during the squat. Attach the other end to the bar.','Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wider for more emphasis on the back, glutes, adductors, and hamstrings, or closer together for more quad development. Keep your head facing forward.','With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips until you are seated on the box. Ideally, your shins should be perpendicular to the ground. Pause when you reach the box, and relax the hip flexors. Never bounce off of a box.','Keeping the weight on your heels and pushing your feet and knees out, drive upward off of the box as you lead the movement with your head. Continue upward, maintaining tightness head to toe. Use care to return the barbell to the rack.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','forearms','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Band Deadlift', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Set the bar up in a power rack. Attach bands to the top of the rack, using either bands pegs or the frame itself. Attach the other end of the bands to the bar.','Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward.','After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['abductors','adductors','calves','glutes','hamstrings','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Band Power Squat', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Begin in a power rack with the pins and bar set at the appropriate height. After loading the bar, attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end of the bands to the bar.','Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings.','Keep your head facing forward. With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.','Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.'], ARRAY['quadriceps'], ARRAY['adductors','calves','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Band Sumo Deadlift', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a bar loaded on the floor inside of a power rack. Attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end to the barbell.','Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.','Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.','As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.','Return the weight to the ground by bending at the hips and controlling the weight on the way down.'], ARRAY['hamstrings'], ARRAY['abductors','adductors','calves','forearms','glutes','lower back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Barbell Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright while holding a barbell at shoulder width with the elbows close to the torso. The palm of your hands should be facing down (pronated grip). This will be your starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Barbell Preacher Curls', 'e-z curl bar', true, 'e-z curl bar', 'intermediate', 'pull', 'isolation', ARRAY['Grab an EZ-bar using a shoulder width and palms down (pronated) grip.','Now place the upper part of both arms on top of the preacher bench and have your arms extended. This will be your starting position.','As you exhale, use the biceps to curl the weight up until your biceps are fully contracted and the barbell is at shoulder height. Squeeze the biceps hard for a second at the contracted position.','As you breathe in, slowly lower the barbell until your upper arms are extended and the biceps is fully stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Cable Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright while holding a bar attachment that is attached to a low pulley using a pronated (palms down) and shoulder width grip. Make sure also that you keep the elbows close to the torso. This will be your starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie down on the floor with your legs fully extended and arms to the side of your torso with the palms on the floor. Your arms should be stationary for the entire exercise.','Move your legs up so that your thighs are perpendicular to the floor and feet are together and parallel to the floor. This is the starting position.','While inhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the floor. At the end of this movement your knees will be touching your chest.','Hold the contraction for a second and move your legs back to the starting position while exhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Flyes', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).','Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.','Maintaining the slight bend of the elbows, move the weights out and away from each other (to the side) in an arc motion while exhaling. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.','The arms should be elevated until they are parallel to the floor.','Feel the contraction and slowly lower the weights back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Flyes With External Rotation', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['To begin, lie down on an incline bench set at a 30-degree angle with the chest and stomach pressing against the incline.','Have the dumbbells in each hand with the palms facing down to the floor. Your arms should be in front of you so that they are perpendicular to the angle of the bench. Tip: Your elbows should have a slight bend. The legs should be stationary while applying pressure with the ball of your toes (your heels should not be touching the floor). This is the starting position.','Maintaining the slight bend of the elbows, move the weights out and away from each other in an arc motion while exhaling.','As you lift the weight, your wrist should externally rotate by 90-degrees so that you go from a palms down (pronated) grip to a palms facing each other (neutral) grip. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.','The arms should be elevated until they are level with the head.','Feel the contraction and slowly lower the weights back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Grip Bent-Over Rows', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Stand erect while holding a barbell with a supinated grip (palms facing up).','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Grip Triceps Pushdown', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Start by setting a bar attachment (straight or e-z) on a high pulley machine.','Facing the bar attachment, grab it with the palms facing up (supinated grip) at shoulder width. Lower the bar by using your lats until your arms are fully extended by your sides. Tip: Elbows should be in by your sides and your feet should be shoulder width apart from each other. This is the starting position.','Slowly elevate the bar attachment up as you inhale so it is aligned with your chest. Only the forearms should move and the elbows/upper arms should be stationary by your side at all times.','Then begin to lower the cable bar back down to the original staring position while exhaling and contracting the triceps hard.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Hyperextension', 'machine', true, 'machine', 'intermediate', 'pull', NULL, ARRAY['Place your feet between the pads after loading an appropriate weight. Lay on the top pad, allowing your hips to hang off the back, while grasping the handles to hold your position.','To begin the movement, flex the hips, pulling the legs forward.','Reverse the motion by extending the hips, kicking the leg back. It is very important not to over-extend the hip on this movement, stopping short of your full range of motion.','Return by again flexing the hip, pulling the carriage forward as far as you can.','Repeat for the desired number of repetitions.'], ARRAY['hamstrings'], ARRAY['calves','glutes'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Machine Flyes', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Adjust the handles so that they are fully to the rear. Make an appropriate weight selection and adjust the seat height so the handles are at shoulder level. Grasp the handles with your hands facing inwards. This will be your starting position.','In a semicircular motion, pull your hands out to your side and back, contracting your rear delts.','Keep your arms slightly bent throughout the movement, with all of the motion occurring at the shoulder joint.','Pause at the rear of the movement, and slowly return the weight to the starting position.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Plate Curls', 'other', true, 'other', 'beginner', 'pull', 'isolation', ARRAY['Start by standing straight with a weighted plate held by both hands and arms fully extended. Use a pronated grip (palms facing down) and make sure your fingers grab the rough side of the plate while your thumb grabs the smooth side. Note: For the best results, grab the weighted plate at an 11:00 and 1:00 o''clock position.','Your feet should be shoulder width apart from each other and the weighted plate should be near the groin area. This is the starting position.','Slowly lift the plate up while keeping the elbows in and the upper arms stationary until your biceps and forearms touch while exhaling. The plate should be evenly aligned with your torso at this point.','Feel the contraction for a second and begin to lower the weight back down to the starting position while inhaling','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Reverse Triceps Bench Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Lie back on a flat bench. Using a close, supinated grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked extended in front of you and perpendicular to the floor. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rickshaw Carry', 'other', true, 'other', 'intermediate', NULL, 'compound', ARRAY['Position the frame at the starting point, and load with the appropriate weight. Standing in the center of the frame, begin by gripping the handles and driving through your heels to lift the frame. Ensure your chest and head are up and your back is straight.','Immediately begin walking briskly with quick, controlled steps. Keep your chest up and head forward, and make sure you continue breathing. Bring the frame to the ground after you have reached the end point.'], ARRAY['forearms'], ARRAY['abdominals','calves','glutes','hamstrings','lower back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rickshaw Deadlift', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Load the frame with the desired weight. Center yourself between the handles. You feet should be about hip width apart. Bend at the hips to grip the handles, allowing your shoulder blades to protract.','With your feet and your grip set, take a big breath and then lower your hips and flex the knees. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward.','Lower the weight by bending at the hips and guiding it to the ground.'], ARRAY['quadriceps'], ARRAY['forearms','glutes','hamstrings','lower back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Ring Dips', 'other', true, 'other', 'intermediate', 'push', 'compound', ARRAY['Grip a ring in each hand, and then take a small jump to help you get into the starting position with your arms locked out.','Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.','Reverse the motion by extending the elbow, pushing yourself back up into the starting position.','Repeat for the desired number of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rocket Jump', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.','To initiate the move, squat down halfway and explode back up as high as possible.','Fully extend your entire body, reaching overhead as far as possible. As you land, absorb your impact through the legs.'], ARRAY['quadriceps'], ARRAY['calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rocking Standing Calf Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place it on the back of your shoulders (slightly below the neck).','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance. Also maintain a straight back and keep the knees with a slight bend; never locked. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending (other than the slight initial bend we created during positioning) at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Now lift your toes by contracting the tibia muscles in the front of the calves as you breathe out.','Hold for a second and bring them back down as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rocky Pull-Ups/Pulldowns', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Grab the pull-up bar with the palms facing forward using a wide grip.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Now repeat the same movements as described above except this time your torso will remain straight as you go up and the bar will touch the back of the neck instead of the upper chest. Tip: Use the head to lean forward slightly as it will help you properly execute this portion of the exercise.','Once you have lowered yourself back down to the starting position, repeat the exercise for the prescribed amount of repetitions in your program.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Romanian Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion.','Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position.','Keeping your back and arms completely straight at all times, use your hips to lift the bar as you exhale. Tip: The movement should not be fast but steady and under control.','Once you are standing completely straight up, lower the bar by pushing the hips back, only slightly bending the knees, unlike when squatting. Tip: Take a deep breath at the start of the movement and keep your chest up. Hold your breath as you lower and exhale as you complete the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['calves','glutes','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Romanian Deadlift from Deficit', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin standing while holding a bar at arm''s length in front of you. You can stand on a raised platform to increase the range of motion.','Begin by flexing the knees slightly, and then flex at the hip, moving your butt back as far as possible, lowering the torso as far as flexibility allows. The back should remain in absolute extension at all times, and the bar should remain in contact with the legs. If done properly, there should be heavy tension felt in the hamstrings.','Reverse the motion to return to the starting position.'], ARRAY['hamstrings'], ARRAY['forearms','glutes','lower back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rope Climb', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Grab the rope with both hands above your head. Pull down on the rope as you take a small jump.','Wrap the rope around one leg, using your feet to pinch the rope. Reach up as high as possible with your arms, gripping the rope tightly.','Release the rope from your feet as you pull yourself up with your arms, bringing your knees towards your chest.','Resecure your feet on the rope, and then stand up to take another high hold on the rope. Continue until you reach the top of the rope.','To lower yourself, loosen the grip of your feet on the rope as you slide down using a hand over hand motion.'], ARRAY['lats'], ARRAY['biceps','forearms','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rope Crunch', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Kneel 1-2 feet in front of a cable system with a rope attached.','After selecting an appropriate weight, grasp the rope with both hands reaching overhead. Your torso should be upright in the starting position.','To begin, flex at the spine, attempting to bring your rib cage to your legs as you pull the cable down.','Pause at the bottom of the motion, and then slowly return to the starting position.','These can be done with twists or to the side to hit the obliques.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rope Jumping', 'other', true, 'other', 'intermediate', NULL, NULL, ARRAY['Hold an end of the rope in each hand. Position the rope behind you on the ground. Raise your arms up and turn the rope over your head bringing it down in front of you. When it reaches the ground, jump over it. Find a good turning pace that can be maintained. Different speeds and techniques can be used to introduce variation.','Rope jumping is exciting, challenges your coordination, and requires a lot of energy. A 150 lb person will burn about 350 calories jumping rope for 30 minutes, compared to over 450 calories running.'], ARRAY['quadriceps'], ARRAY['calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rope Straight-Arm Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Attach a rope to a high pulley and make your weight selection. Stand a couple feet back from the pulley with your feet staggered and take the rope with both hands. Lean forward from the hip, keeping your back straight, with your arms extended up in front of you. This will be your starting position.','Keeping your arms straight, extend the shoulder to pull the rope down to your thighs.','Pause at the bottom of the motion, squeezing your lats.','Return to the starting position without allowing the weight to fully rest on the stack.'], ARRAY['lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Rowing, Stationary', 'machine', true, 'machine', 'intermediate', NULL, NULL, ARRAY['To begin, seat yourself on the rower. Make sure that your heels are resting comfortably against the base of the foot pedals and that the straps are secured. Select the program that you wish to use, if applicable. Sit up straight and bend forward at the hips.','There are three phases of movement when using a rower. The first phase is when you come forward on the rower. Your knees are bent and against your chest. Your upper body is leaning slightly forward while still maintaining good posture. Next, push against the foot pedals and extend your legs while bringing your hands to your upper abdominal area, squeezing your shoulders back as you do so. To avoid straining your back, use primarily your leg and hip muscles.','The recovery phase simply involves straightening your arms, bending the knees, and bringing your body forward again as you transition back into the first phase.'], ARRAY['quadriceps'], ARRAY['biceps','calves','glutes','hamstrings','lower back','middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Running, Treadmill', 'machine', true, 'machine', 'beginner', NULL, NULL, ARRAY['To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','Treadmills offer convenience, cardiovascular benefits, and usually have less impact than running outside. A 150 lb person will burn over 450 calories running 8 miles per hour for 30 minutes. Maintain proper posture as you run, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Russian Twist', 'body only', true, 'body only', 'intermediate', 'pull', 'compound', ARRAY['Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.','Elevate your upper body so that it creates an imaginary V-shape with your thighs. Your arms should be fully extended in front of you perpendicular to your torso and with the hands clasped. This is the starting position.','Twist your torso to the right side until your arms are parallel with the floor while breathing out.','Hold the contraction for a second and move back to the starting position while breathing out. Now move to the opposite side performing the same techniques you applied to the right side.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY['lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sandbag Load', 'other', true, 'other', 'beginner', 'pull', 'compound', ARRAY['To load sandbags or other objects, begin with the implements placed a distance from the loading platform, typically 50 feet.','Begin by lifting the sandbag. Sandbags are extremely awkward, and the manner of lifting them can vary depending on the particular sandbag used. Reach as far around it as possible, extending through the hips and knees to pull it up high. Shouldering is usually not allowed.','Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible. Place it onto the platform, ensuring it doesn''t fall off.','Return to the starting position to retrieve the next sandbag, and repeat until the event is completed.'], ARRAY['quadriceps'], ARRAY['abdominals','biceps','calves','forearms','glutes','hamstrings','lower back','middle back','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Scapular Pull-Up', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Take a pronated grip on a pull-up bar.','From a hanging position, raise yourself a few inches without using your arms. Do this by depressing your shoulder girdle in a reverse shrugging motion.','Pause at the completion of the movement, and then slowly return to the starting position before performing more repetitions.'], ARRAY['traps'], ARRAY['lats','middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Scissors Jump', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Assume a lunge stance position with one foot forward with the knee bent, and the rear knee nearly touching the ground.','Ensure that the front knee is over the midline of the foot. Extending through both legs, jump as high as possible, swinging your arms to gain lift.','As you jump as high as you can, switch the position of your legs, moving your front leg to the back and the rear leg to the front.','As you land, absorb the impact through the legs by adopting the lunge position, and repeat.'], ARRAY['quadriceps'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Band Hamstring Curl', 'other', true, 'other', 'beginner', 'pull', 'isolation', ARRAY['Secure a band close to the ground and place a bench a couple feet away from it.','Seat yourself on the bench and secure the band behind your ankles, beginning with your legs straight. This will be your starting position.','Flex the knees, bringing your feet towards the bench. You may need to lean back slightly to keep your feet from striking the floor.','Pause at the completion of the movement, and then slowly return to the starting position.'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Barbell Military Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Sit on a Military Press Bench with a bar behind your head and either have a spotter give you the bar (better on the rotator cuff this way) or pick it up yourself carefully with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down.','Once you pick up the barbell with the correct grip length, lift the bar up over your head by locking your arms. Hold at about shoulder level and slightly in front of your head. This is your starting position.','Lower the bar down to the collarbone slowly as you inhale.','Lift the bar back up to the starting position as you exhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Barbell Twist', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by sitting at the end of a flat bench with a barbell placed on top of your thighs. Your feet should be shoulder width apart from each other.','Grip the bar with your palms facing down and make sure your hands are wider than shoulder width apart from each other. Begin to lift the barbell up over your head until your arms are fully extended.','Now lower the barbell behind your head until it is resting along the base of your neck. This is the starting position.','While keeping your feet and head stationary, move your waist from side to side so that your oblique muscles feel the contraction. Only move from side to side as far as your waist will allow you to go. Stretching or moving too far can cause an injury to occur. Tip: Use a slow and controlled motion.','Remember to breathe out while twisting your body to the side and in when moving back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Bent-Over One-Arm Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Sit down at the end of a flat bench with a dumbbell in one arm using a neutral grip (palms of the hand facing you).','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.','The upper arm with the dumbbell should be close to the torso and aligned with it (lifted up until it is parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.','Keeping the upper arm stationary, use the triceps to lift the weight as you exhale until the forearm is parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.','After a second contraction at the top, slowly lower the dumbbell back to the starting position as you inhale.','Repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the exercise.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Bent-Over Rear Delt Raise', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Place a couple of dumbbells looking forward in front of a flat bench.','Sit on the end of the bench with your legs together and the dumbbells behind your calves.','Bend at the waist while keeping the back straight in order to pick up the dumbbells. The palms of your hands should be facing each other as you pick them. This will be your starting position.','Keeping your torso forward and stationary, and the arms slightly bent at the elbows, lift the dumbbells straight to the side until both arms are parallel to the floor. Exhale as you lift the weights. (Note: avoid swinging the torso or bringing the arms back as opposed to the side.)','After a one second contraction at the top, slowly lower the dumbbells back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Bent-Over Two-Arm Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Sit down at the end of a flat bench with a dumbbell in both arms using a neutral grip (palms of the hand facing you).','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Make sure that you keep the head up.','The upper arms with the dumbbells should be close to the torso and aligned with it (lifted up until they are parallel to the floor while the forearms are pointing towards the floor as the hands hold the weights). Tip: There should be a 90-degree angle between the forearms and the upper arm. This is your starting position.','Keeping the upper arms stationary, use the triceps to lift the weight as you exhale until the forearms are parallel to the floor and the whole arm is extended. Like many other arm exercises, only the forearm moves.','After a second contraction at the top, slowly lower the dumbbells back to the starting position as you inhale.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Cable Rows', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['For this exercise you will need access to a low pulley row machine with a V-bar. Note: The V-bar will enable you to have a neutral grip where the palms of your hands face each other. To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.','Lean over as you keep the natural alignment of your back and grab the V-bar handles.','With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.','Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'], ARRAY['Sit tall, slight forward lean at start','Pull handle to lower chest','Squeeze shoulder blades together, hold 1 sec','Dont let weight yank you forward on return','Keep chest up and proud'], ARRAY['Excessive body swing','Pulling too high','Rounding upper back','Not controlling the eccentric'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Cable Shoulder Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 90 degrees to the body, with your head and chest up. The elbows should also be bent to about 90 degrees. This will be your starting position.','Begin by extending through the elbow, pressing the handles together above your head.','After pausing at the top, return the handles to the starting position. Ensure that you maintain tension on the cables.','You can also execute this movement with your back off the pad and alternate hands.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Calf Raise', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Sit on the machine and place your toes on the lower portion of the platform provided with the heels extending off. Choose the toe positioning of your choice (forward, in, or out) as per the beginning of this chapter.','Place your lower thighs under the lever pad, which will need to be adjusted according to the height of your thighs. Now place your hands on top of the lever pad in order to prevent it from slipping forward.','Lift the lever slightly by pushing your heels up and release the safety bar. This will be your starting position.','Slowly lower your heels by bending at the ankles until the calves are fully stretched. Inhale as you perform this movement.','Raise the heels by extending the ankles as high as possible as you contract the calves and breathe out. Hold the top contraction for a second.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Close-Grip Concentration Barbell Curl', 'barbell', true, 'barbell', 'intermediate', 'pull', 'isolation', ARRAY['Sit down on a flat bench with a barbell or E-Z Bar in front of you in between your legs. Your legs should be spread with the knees bent and the feet on the floor.','Use your arms to pick the barbell up and place the back of your upper arms on top of your inner thighs (around three and a half inches away from the front of the knee). A supinated grip closer than shoulder width is needed to perform this exercise. Tip: Your arm should be extended at arms length and the barbell should be above the floor. This will be your starting position.','While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the barbell back to starting position as your breathe in. Tip: Avoid swinging motions at any time.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Dumbbell Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit on a flat bench with a dumbbell on each hand being held at arms length. The elbows should be close to the torso.','Rotate the palms of the hands so that they are facing your torso. This will be your starting position.','While holding the upper arm stationary, curl the weights and start twisting the wrists once the dumbbells pass your thighs so that the palms of your hands face forward at the end of the movement. Make sure that you contract the biceps as you breathe out and make sure that only the forearms move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the dumbbells back to the starting position as your breathe in and as you rotate the wrists back to a neutral grip.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Dumbbell Inner Biceps Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit on the end of a flat bench with a dumbbell in each hand being held at arms length. The elbows should be close to the torso.','Rotate the palms of the hands so that they are facing inward in a neutral position. This will be your starting position.','While holding the upper arms stationary, curl the dumbbells out and up, turning the palms out as you lift and keeping your forearms in line with your outer deltoids. Tips:','Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the dumbbells back to the starting position as your breathe in. Remember to rotate your arms as you lower the dumbbells so that you can switch back to a neutral grip.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Dumbbell Palms-Down Wrist Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on the floor in front of a flat bench.','Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.','Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing down. Your wrists should be hanging over the edge of your thighs.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.','When finished, simply lower the dumbbells to the floor.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Dumbbell Palms-Up Wrist Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on the floor in front of a flat bench.','Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.','Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing up. Your wrists should be hanging over the edge of your thighs.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.','When finished, simply lower the dumbbells to the floor.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Dumbbell Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Grab a couple of dumbbells and sit on a military press bench or a utility bench that has a back support on it as you place the dumbbells upright on top of your thighs.','Clean the dumbbells up one at a time by using your thighs to bring the dumbbells up to shoulder height at each side.','Rotate the wrists so that the palms of your hands are facing forward. This is your starting position.','As you exhale, push the dumbbells up until they touch at the top.','After a second pause, slowly come down back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Flat Bench Leg Pull-In', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.','Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.','After a second pause, go back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Good Mornings', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Set up a box in a power rack. The pins should be set at an appropriate height. Begin by stepping under the bar and placing it across the back of the shoulders, not on top of your traps. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders.','Remove the bar from the rack, creating a tight arch in your lower back. Keep your head facing forward. With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips until you are seated on the box. This will be your starting position.','Keeping the bar tight, bend forward at the hips as much as possible. If you set the pins to what would be parallel, you not only have a safety if you fail, but know when to stop.','Pause just above the pins and reverse the motion until your torso it upright.'], ARRAY['lower back'], ARRAY['glutes'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Head Harness Neck Resistance', 'other', true, 'other', 'intermediate', 'pull', 'isolation', ARRAY['Place a neck strap on the floor at the end of a flat bench. Once you have selected the weights, sit at the end of the flat bench with your feet wider than shoulder width apart from each other. Your toes should be pointed out.','Slowly move your torso forward until it is almost parallel with the floor. Using both hands, securely position the neck strap around your head. Tip: Make sure the weights are still lying on the floor to prevent any strain on the neck. Now grab the weight with both hands while elevating your torso back until it is almost perpendicular to the floor. Note: Your head and torso needs to be slightly tilted forward to perform this exercise.','Now place both hands on top of your knees. This is the starting position.','Slowly lower your neck down until your chin touches the upper part of your chest while breathing in.','While exhaling, bring your neck back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['neck'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Leg Curl', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Adjust the machine lever to fit your height and sit on the machine with your back against the back support pad.','Place the back of lower leg on top of padded lever (just a few inches under the calves) and secure the lap pad against your thighs, just above the knees. Then grasp the side handles on the machine as you point your toes straight (or you can also use any of the other two stances) and ensure that the legs are fully straight right in front of you. This will be your starting position.','As you exhale, pull the machine lever as far as possible to the back of your thighs by flexing at the knees. Keep your torso stationary at all times. Hold the contracted position for a second.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Leg Tucks', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Sit on a bench with the legs stretched out in front of you slightly below parallel and your arms holding on to the sides of the bench. Your torso should be leaning backwards around a 45-degree angle from the bench. This will be your starting position.','Bring the knees in toward you as you move your torso closer to them at the same time. Breathe out as you perform this movement.','After a second pause, go back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated One-Arm Dumbbell Palms-Down Wrist Curl', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'isolation', ARRAY['Sit on a flat bench with a dumbbell in your right hand.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your right forearm on top of your upper right thigh with your palm down. Tip: Make sure that the back of the wrist lies on top of your knees. This will be your starting position.','Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.','Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.','Perform for the recommended amount of repetitions, switch arms and repeat the movement.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated One-Arm Dumbbell Palms-Up Wrist Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit on a flat bench with a dumbbell in your right hand.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your right forearm on top of your upper right thigh with your palm up. Tip: Make sure that the front of the wrist lies on top of your knees. This will be your starting position.','Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.','Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.','Perform for the recommended amount of repetitions, switch arms and repeat the movement.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated One-arm Cable Pulley Rows', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.','Lean over as you keep the natural alignment of your back and grab the single handle attachment with your left arm using a palms-down grip.','With your arm extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lat as you hold the bar in front of you. The right arm can be kept by the waist. This is the starting position of the exercise.','Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it as you rotate the wrist, so that by the time your hand is by your abdominals it is in a neutral position (palms facing the torso). Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard.','Hold that contraction for a second and slowly go back to the original position while breathing in. Tip: Remember to rotate the wrist as you go back to the starting position so that the palms are facing down again.','Repeat for the recommended amount of repetitions and then perform the same movement with the right hand.'], ARRAY['middle back'], ARRAY['biceps','lats','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Palm-Up Barbell Wrist Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your forearms on top of your upper thighs with your palms up. Tip: Make sure that the front of the wrists lay on top of your knees. This will be your starting position.','Lower the bar as far as possible while inhaling and keeping a tight grip.','Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Palms-Down Barbell Wrist Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your forearms on top of your upper thighs with your palms down. Tip: Make sure that the back of the wrists lay on top of your knees. This will be your starting position.','Lower the bar as far as possible while inhaling and keeping a tight grip.','Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Side Lateral Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Pick a couple of dumbbells and sit at the end of a flat bench with your feet firmly on the floor. Hold the dumbbells with your palms facing in and your arms straight down at your sides at arms'' length. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.','Lower the dumbbells back down slowly to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Triceps Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Sit down on a bench with back support and grasp a dumbbell with both hands and hold it overhead at arm''s length. Tip: a better way is to have somebody hand it to you especially if it is very heavy. The resistance should be resting in the palms of your hands with your thumbs around it. The palm of the hand should be facing inward. This will be your starting position.','Keeping your upper arms close to your head (elbows in) and perpendicular to the floor, lower the resistance in a semi-circular motion behind your head until your forearms touch your biceps. Tip: The upper arms should remain stationary and only the forearms should move. Breathe in as you perform this step.','Go back to the starting position by using the triceps to raise the dumbbell. Breathe out as you perform this step.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Seated Two-Arm Palms-Up Low-Pulley Wrist Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Put a bench in front of a low pulley machine that has a barbell or EZ Curl attachment on it.','Move the bench far enough away so that when you bring the handle to the top of your thighs tension is created on the cable due to the weight stack being moved up.','Now hold the handle with both hands, palms up, using a shoulder-width grip.','Step back and sit on the bench with your feet about shoulder width apart, firmly on the floor.','Lean forward and place the forearms on your thighs with the back of your wrists over your knees. This will be your starting position.','Lower the bar as far as possible, while inhaling and keeping a tight grip.','Now curl the bar up as high as possible while contracting the forearms. Tip: Only the wrist should move; not the forearms.','After a second contraction at the top go back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('See-Saw Press (Alternating Side Press)', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Grab a dumbbell with each hand and stand up erect.','Clean (lift) the dumbbells to the chest/shoulder level and then rotate your wrists so that your palms are facing towards you as if you were getting ready to perform an Arnold Press. This will be your starting position.','Now start extending your left arm overhead as you rotate the wrist so that the palm of your hand faces forward as you go up. Your elbows should come out also as you lift the weight. Simultaneously, you will also be bending from your hip to your opposite side. Tip: If you perform the exercise correctly, is should look as if you are trying to reach for something overhead on the right hand side of your body, but with your left arm. Breathe out as you perform this movement.','Once you reach the top position breathe in. Then, with the weight fully extended overhead and you bent over to your right hand side, begin the movement to the left side.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['abdominals','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Shotgun Row', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Attach a single handle to a low cable.','After selecting the correct weight, stand a couple feet back with a wide-split stance. Your arm should be extended and your shoulder forward. This will be your starting position.','Perform the movement by retracting the shoulder and flexing the elbow. As you pull, supinate the wrist, turning the palm upward as you go.','After a brief pause, return to the starting position.'], ARRAY['lats'], ARRAY['biceps','middle back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Shoulder Press - With Bands', 'bands', true, 'bands', 'beginner', 'push', 'compound', ARRAY['To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles and lift them so that the hands are at shoulder height at each side.','Rotate the wrists so that the palms of your hands are facing forward. Your elbows should be bent, with the upper arms and forearms in line to the torso. This is your starting position.','As you exhale, lift the handles up until your arms are fully extended overhead.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side Bridge', 'body only', true, 'body only', 'beginner', 'static', NULL, ARRAY[]::TEXT[], ARRAY['abdominals'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side Hop-Sprint', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand to the side of a cone or hurdle.','Begin this drill by hopping sideways over the obstacle, rebounding out of your landing to hop back to where you started.','Hop for a prescribed number or repetitions as quickly as possible, and finish this drill by sprinting a short distance upon landing the last hop.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side Jackknife', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY[]::TEXT[], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side Lateral Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Pick a couple of dumbbells and stand with a straight torso and the dumbbells by your side at arms length with the palms of the hand facing you. This will be your starting position.','While maintaining the torso in a stationary position (no swinging), lift the dumbbells to your side with a slight bend on the elbow and the hands slightly tilted forward as if pouring water in a glass. Continue to go up until you arms are parallel to the floor. Exhale as you execute this movement and pause for a second at the top.','Lower the dumbbells back down slowly to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side Laterals to Front Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['In a standing position, hold a pair of dumbbells at your side. This will be your starting position.','Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.','At the top of the exercise move the weights out in front of you, keeping your arms extended.','Lower the weights with a controlled motion.','On the next repetition, raise the weights in front of you to shoulder height before moving the weights laterally to your sides.','Lower the weights to the starting position.'], ARRAY['shoulders'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side Standing Long Jump', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Begin standing with your feet hip width apart in an athletic stance. Your head and chest should be up, knees and hips slightly bent. This will be your starting position.','Leaning to your right, extend through your hips, knees, and ankles to jump into the air. Block with the arms to lead the movement, jumping as far to your right as you can.','Land facing the same direction with your feet hip width apart, absorbing the impact through your lower body.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side To Side Chins', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['Grab the pull-up bar with the palms facing forward using a wide grip.','As you have both arms extended in front of you holding the bar at a wide grip, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up while leaning to the left hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space (no swinging) and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of contraction, inhale as you go back to the starting position.','Now, pull your torso up while leaning to the right hand side until the bar almost touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of contraction, inhale as you go back to the starting position.','Repeat steps 3-6 until you have performed the prescribed amount of repetitions for each side.'], ARRAY['lats'], ARRAY['biceps','forearms','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Side to Side Box Shuffle', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand to one side of the box with your left foot resting on the middle of it.','To begin, jump up and over to the other side of the box, landing with your right foot on top of the box and your left foot on the floor. Swing your arms to aid your movement.','Continue shuffling back and forth across the box.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Arm Cable Crossover', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand.','Step forward in front of both pulleys with your arms extended in front of you, bringing your hands together. Your head and chest should be up as you lean forward, while your feet should be staggered. This will be your starting position.','Keeping your left arm in place, allow your right arm to extend out to the side, maintaining a slight bend at the elbow. The right arm should be perpendicular to the body at approximately shoulder level.','Return your arm back to the starting position by pulling your hand back to the midline of the body.','Hold for a second at the starting position and repeat the movement on the opposite side. Continue alternating back and forth for the prescribed number of repetitions.'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Arm Linear Jammer', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.','Raise the bar from the floor, taking it to your shoulders with one or both hands. Adopt a wide stance. This will be your starting position.','Perform the movement by extending the elbow, pressing the weight up. Move explosively, extending the hips and knees fully to produce maximal force.','Return to the starting position.'], ARRAY['shoulders'], ARRAY['chest','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Arm Push-Up', 'body only', true, 'body only', 'intermediate', 'push', 'compound', ARRAY['Begin laying prone on the ground. Move yourself into a position supporting your weight on your toes and one arm. Your working arm should be placed directly under the shoulder, fully extended. Your legs should be extended, and for this movement you may need a wider base, placing your feet further apart than in a normal push-up.','Maintain good posture, and place your free hand behind your back. This will be your starting position.','Lower yourself by allowing the elbow to flex until you touch the ground.','Descend slowly, and reverse direction be extending the arm to return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Cone Sprint Drill', 'other', true, 'other', 'beginner', 'push', NULL, ARRAY['This drill teaches quick foot action. You need a single cone. Begin standing next to the cone with one arm back and one arm forward.','Chop the feet as quickly as possible, blocking with the arms. Circle the cone, keep your knees up, with violent foot action.','Rest after three trips around the cone.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Leg High Box Squat', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Position a box in a rack. Secure a band or rope in place above the box.','Standing in front of it, step onto the box to a full standing position, letting your other leg remain unsupported. Hold onto the band for balance','. Continue stepping up and down on the same leg before switching to the opposite side.'], ARRAY['quadriceps'], ARRAY['glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Leg Hop Progression', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Arrange a line of cones in front of you. Assume a relaxed standing position, balanced on one leg. Raise the knee of your opposite leg. This will be your starting position.','Hop forward, jumping and landing with the same leg over the cone.','Use a countermovement jump to hop from cone to cone.','At the end, turn around and go back on the other leg.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Leg Lateral Hop', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand to the side of a cone or hurdle. To get into the start position, stand on one leg with your knee slightly bent.','To begin, execute a counterjump to hop sideways over the cone.','Land on your jumping leg, and immediately rebound out of it by jumping back to the start position.','Continue hopping back and forth.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Leg Leg Extension', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Seat yourself in the machine and adjust it so that you are positioned properly. The pad should be against the lower part of the shin but not in contact with the ankle. Adjust the seat so that the pivot point is in line with your knee. Select a weight appropriate for your abilities.','Maintaining good posture, fully extend one leg, pausing at the top of the motion.','Return to the starting position without letting the weight stop, keeping tension on the muscle.','Repeat for the desired number of repetitions.'], ARRAY['quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single-Leg Stride Jump', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand to the side of a box with your inside foot on top of it, close to the edge.','Begin by swinging the arms upward as you push through the top leg, jumping upward as high as possible. Attempt to drive the opposite knee upward.','Land in the same position that you started, using your inside leg to decelerate the impact.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single Dumbbell Raise', 'dumbbell', true, 'dumbbell', 'beginner', NULL, 'isolation', ARRAY['With a wide stance, hold a dumbell with both hands, grasping the head of the dumbbell instead of the handle. Your arms should be extended and hanging at the waist. This will be your starting position.','Raise the weight until it is above shoulder level, keeping your arms extended. Your torso and hips should remain stationary throughout the movement.','Return to the starting position and repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['forearms','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single Leg Butt Kick', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Begin by standing on one leg, with the bent knee raised. This will be your start position.','Using a countermovement jump, take off upward by extending the hip, knee, and ankle of the grounded leg.','Immediately flex the knee and attempt to touch your butt with the heel of your jumping leg.','Return the leg to a partially bent position underneath the hips and land. Your opposite leg should stay in relatively the same position throughout the drill.'], ARRAY['quadriceps'], ARRAY['calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single Leg Glute Bridge', 'body only', true, 'body only', 'beginner', 'push', 'isolation', ARRAY['Lay on the floor with your feet flat and knees bent.','Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position.','Execute the movement by driving through the heel, extending your hip upward and raising your glutes off of the ground.','Extend as far as possible, pause and then return to the starting position.'], ARRAY['glutes'], ARRAY['hamstrings'], ARRAY['One foot flat, other leg extended','Drive hips up using one leg','Squeeze glute hard at top','Keep hips level, dont rotate','Great for finding glute imbalances'], ARRAY['Hips tilting to one side','Pushing through toes','Not going high enough'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Single Leg Push-off', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Stand on the ground with one foot resting on the box, heel close to the edge.','Push off with your foot on top of the box, trying to gain as much height as possible by extending through the hip and knee.','Land with the same foot on top of the box, returning your other foot back to the start position.'], ARRAY['quadriceps'], ARRAY['calves','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sit-Up', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie down on the floor placing your feet either under something that will not move or by having a partner hold them. Your legs should be bent at the knees.','Place your hands behind your head and lock them together by clasping your fingers. This is the starting position.','Elevate your upper body so that it creates an imaginary V-shape with your thighs. Breathe out when performing this part of the exercise.','Once you feel the contraction for a second, lower your upper body back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Skating', 'other', true, 'other', 'intermediate', NULL, NULL, ARRAY['Roller skating is a fun activity which can be effective in improving cardiorespiratory fitness and muscular endurance. It requires relatively good balance and coordination. It is necessary to learn the basics of skating including turning and stopping and to wear protective gear to avoid possible injury.','You can skate at a comfortable pace for 30 minutes straight. If you want a cardio challenge, do interval skating — speed skate two minutes of every five minutes, using the remaining three minutes to recover. A 150 lb person will typically burn about 175 calories in 30 minutes skating at a comfortable pace, similar to brisk walking.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sled Drag - Harness', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['To begin, load the sled with the desired weight and attach the pulling strap. You can pull with handles, use a harness, or attach the pulling strap to a weight belt.','Whether pulling forwards or backwards, lean in the direction of travel and progress by extending through the hips and knees.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sled Overhead Backward Walk', 'other', true, 'other', 'beginner', 'pull', 'compound', ARRAY['Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.','Face the sled, backing up until there is some tension in the line. Hold your hands directly above your head with your elbows extended. This will be your starting position.','Walk backwards, keeping your arms raised above your head. Avoid jerky movements.'], ARRAY['shoulders'], ARRAY['calves','middle back','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sled Overhead Triceps Extension', 'other', true, 'other', 'beginner', 'push', 'isolation', ARRAY['Attach dual handles to a sled using a chain or rope. Load the sled to an appropriate load.','Facing away from the sled, step away until there is tension in the line. Raise your hands above your head, keeping them together, palms facing each other. Your elbows should be pointed upward with the elbows flexed. This will be your starting position.','Extend through the elbow to straighten the arm. Ensure that your upper arm stays in position to isolate the triceps.','Upon full extension, step forward to take the slack out of the line. You may keep your feet staggered for more stability.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sled Push', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['Load your pushing sled with the desired weight.','Take an athletic posture, leaning into the sled with your arms fully extended, grasping the handles. Push the sled as fast as possible, focusing on extending your hips and knees to strengthen your posterior chain.'], ARRAY['quadriceps'], ARRAY['calves','chest','glutes','hamstrings','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sled Reverse Flye', 'other', true, 'other', 'beginner', 'pull', 'isolation', ARRAY['Attach dual handles to a sled connected by a rope or chain. Load the sled to a light weight.','Face the sled, backing up until there is some tension in the line. Take both handles at arms length at about waist level. Bend the knees slightly and keep your chest and head up. This will be your starting position.','Without flexing the elbow, pull the handles upward and apart, performing a reverse fly with some external rotation. Your palms should be facing forward as you do this.','Return to the starting position, taking a couple steps back to take the slack out of the line.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sled Row', 'other', true, 'other', 'beginner', 'pull', 'compound', ARRAY['Attach dual handles to a sled connected by a rope or chain. Load the sled to an appropriate weight. Face the sled, backing up until there is some tension in the line.','With a handle in each hand, bend the knees slightly, keep your head and chest up, and begin with your arms extended.','To initiate the movement, flex the elbow as you retract your shoulder blades, pulling the sled towards you.','Take a step or two back to get tension in the line and repeat.'], ARRAY['middle back'], ARRAY['biceps','lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Sledgehammer Swings', 'other', true, 'other', 'beginner', 'pull', 'compound', ARRAY['You will need a tire and a sledgehammer for this exercise. Stand in front of the tire about two feet away from it with a staggered stance. Grip the sledgehammer.','If you are right handed, your left hand should be at the bottom of the handle, and your right hand should be choking up closer to the head.','As you bring the sledge up, your right hand slides toward the head; as you swing down, your right hand will slide down to join your left hand. Slam it down as hard as you can against the tire. Control the bounce of the hammer off of the tire.','Repeat on the other side.'], ARRAY['abdominals'], ARRAY['calves','forearms','lats','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Incline Shoulder Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your shoulders are aligned right under the barbell.','Using a shoulder width pronated (palms forward) grip, lift the bar from the rack and hold it straight over you with a slight bend at the elbows. This will be your starting position.','As you breathe out, lift the bar up until your arms are fully extended. Note: The contraction should be felt around the shoulders.','After a second pause, bring the bar back down to the starting position as you breathe in.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['shoulders'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Behind the Back Shrug', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['With the bar at thigh level, load an appropriate weight.','Stand with the bar behind you, taking a shoulder-width, pronated grip on the bar and unhook the weight. You should be standing up straight with your head and chest up and your arms extended. This will be your starting position.','Initiate the movement by shrugging your shoulders straight up. Do not flex the arms or wrist during the movement.','After a brief pause return the weight to the starting position.','Repeat for the desired number of repetitions before engaging the hooks to rack the weight.'], ARRAY['traps'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Smith Machine Bench Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place a flat bench underneath the smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, lock the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
